// Import n8n's native mammoth library to parse docx files
const mammoth = require('mammoth');

const items = $input.all();
const returnData = [];

for (let i = 0; i < items.length; i++) {
  // 1. Target the binary file named 'data' from the Google Drive node
  const binaryPropertyName = 'data';

  if (!items[i].binary || !items[i].binary[binaryPropertyName]) {
    throw new Error("No binary data found under the property 'data'. Verify your Google Drive node output connection.");
  }

  // 2. Use n8n's native helper function to extract the file stream safely into a buffer
  const fileBuffer = await this.helpers.getBinaryDataBuffer(i, binaryPropertyName);

  // 3. Configure options to drop embedded images from the text stream cleanly
  const options = {
    convertImage: mammoth.images.imgElement(function(image) {
      return {}; 
    })
  };

  // 4. Extract plain text from the Word document layout
  const result = await mammoth.extractRawText({ buffer: fileBuffer }, options);
  const textContent = result.value;

  // 5. Package the text content and filename for the DeepSeek AI model
  returnData.push({
    json: {
      text: textContent,
      name: items[i].binary[binaryPropertyName].fileName || "unknown_sop.docx"
    }
  });
}

return returnData;
